const root = document.getElementById('ui-root')!;

let onStartCb: (() => void) | null = null;
let onResumeCb: (() => void) | null = null;
let onStartCouchCb: (() => void) | null = null;

export function bindActions(opts: {
  onStart: () => void;
  onResume: () => void;
  onStartCouch?: () => void;
}): void {
  onStartCb = opts.onStart;
  onResumeCb = opts.onResume;
  onStartCouchCb = opts.onStartCouch ?? null;
}

/** Start a two-player couch run in place (no reload), enabling couch input
 *  routing at runtime. Used by the booth dual-login so both signed-in
 *  identities survive. Falls back to the normal start if unbound. */
function startCouchInPlace(): void {
  (onStartCouchCb ?? onStartCb)?.();
}

export function renderSignerRecovery(
  state: GameState,
  opts: {
    heading?: string;
    sub?: string;
    onResolved?: (s: SignetSession) => void;
    onClose?: () => void;
  } = {},
): void {
  clearOverlay();
  const overlay = el('div', { className: 'overlay', parent: root });
  setupOverlayArrowNav(overlay);

  el('h2', { parent: overlay, text: opts.heading ?? 'SIGNER NOT LIVE' });
  const sub = el('p', {
    parent: overlay,
    text: opts.sub ?? 'My Signet proved who you are, but Pallasite still needs a signer that can approve game events.',
  });
  sub.style.cssText = 'font-size:0.88rem;color:rgba(220,210,255,0.75);margin:6px auto 18px;max-width:560px;text-align:center;line-height:1.5;';

  const status = el('p', { parent: overlay });
  status.style.cssText = 'font-size:0.82rem;color:rgba(180,140,255,0.86);min-height:1.3em;margin:0 0 12px;text-align:center;letter-spacing:0.04em;';

  const row = el('div', { className: 'menu-row', parent: overlay });
  const buttons: HTMLButtonElement[] = [];
  const makeButton = (label: string, secondary = false): HTMLButtonElement => {
    const btn = el('button', { className: secondary ? 'menu-btn secondary' : 'menu-btn', parent: row, text: label }) as HTMLButtonElement;
    buttons.push(btn);
    return btn;
  };

  const setBusy = (busy: boolean): void => {
    for (const btn of buttons) btn.disabled = busy;
  };
  const finish = (session: SignetSession): void => {
    if (opts.onResolved) opts.onResolved(session);
    else state.session = session;
    (opts.onClose ?? (() => renderTitle(state)))();
  };
  const run = async (method: auth.SignInMethod, label: string): Promise<void> => {
    setBusy(true);
    status.textContent = `Opening ${label}...`;
    status.style.color = 'rgba(180,140,255,0.86)';
    try {
      const session = await auth.signInWith(method);
      if (session) {
        finish(session);
        return;
      }
      status.textContent = 'No live signer attached. Try another method.';
      status.style.color = '#ff8a3a';
    } catch (err) {
      if (auth.isAuthOnlySignerError(err)) {
        status.textContent = 'That Signet approval was still auth-only. Use a live bunker, extension, or Signet QR from another device.';
        status.style.color = '#ffd84a';
      } else {
        status.textContent = err instanceof auth.SignInTimeoutError
          ? `Timeout - ${err.message}`
          : `Sign-in failed: ${err instanceof Error ? err.message : String(err)}`;
        status.style.color = '#ff5050';
      }
    } finally {
      setBusy(false);
    }
  };

  const qrBtn = makeButton('SIGNET QR');
  qrBtn.addEventListener('click', () => { void run('qr', 'Signet QR'); });
  const bunkerBtn = makeButton('PASTE BUNKER', true);
  bunkerBtn.addEventListener('click', () => { void run('bunker', 'bunker'); });
  if (typeof window !== 'undefined' && 'nostr' in window && Boolean((window as { nostr?: unknown }).nostr)) {
    const extBtn = makeButton('EXTENSION', true);
    extBtn.addEventListener('click', () => { void run('nip07', 'extension'); });
  }
  const backBtn = makeButton('BACK', true);
  backBtn.addEventListener('click', () => (opts.onClose ?? (() => renderTitle(state)))());
}

/** Programmatically trigger the bound start callback (the same code path
 *  the IGNITE button takes). Used by duel mode to auto-start both clients
 *  the moment peer-joined fires, so the two sims advance in lockstep
 *  without either player having to hit IGNITE first. No-op if no callback
 *  is bound yet. */
export function simulateStart(): void {
  onStartCb?.();
}

type ConnectingMatchKind = 'duel' | 'coop-campaign' | 'deathmatch';

/** Show a "Connecting to duel" placeholder while peer.connect() is in
 *  flight. The overlay is cleared by simulateStart()'s subsequent
 *  clearOverlay() call (via onStartCb → clearOverlay), so there's no
 *  flicker between this and the game's first render. */
export function renderDuelConnecting(slot: number, players = 2, spectating = false, kind: ConnectingMatchKind = 'duel'): void {
  clearOverlay();
  const overlay = el('div', { className: 'overlay', parent: root });
  setupOverlayArrowNav(overlay);

  const card = el('div', { parent: overlay });
  card.style.cssText = 'display:flex;flex-direction:column;align-items:center;gap:14px;padding:24px 28px;border-radius:10px;border:1px solid rgba(184,144,255,0.35);background:rgba(15,8,32,0.55);max-width:420px;text-align:center;';

  const waitingForHost = !spectating && slot > 0;
  el('h2', { parent: card, text: waitingForHost ? 'WAITING FOR HOST' : 'CONNECTING' }).style.cssText = 'margin:0;font-size:1.45rem;letter-spacing:0.2em;color:var(--hud-yellow);';
  const otherPilots = Math.max(1, players - 1);
  const waitingText = spectating
    ? `Waiting for ${players > 2 ? `${players} pilots` : 'the pilots'} to join the arena.`
    : waitingForHost
      ? kind === 'coop-campaign'
        ? 'Co-pilot connected. Waiting for the host to start the co-op run.'
        : 'Pilot connected. Waiting for the host to start the game.'
    : kind === 'coop-campaign'
      ? 'Waiting for your co-pilot to join the campaign.'
    : players > 2
      ? `Waiting for ${otherPilots} other pilot${otherPilots === 1 ? '' : 's'} to join the arena.`
      : 'Waiting for opponent to join the arena.';
  el('p', { parent: card, text: waitingText })
    .style.cssText = 'margin:0;font-size:0.9rem;color:rgba(220,210,255,0.8);line-height:1.5;';

  const slotChip = el('p', { parent: card, text: spectating ? `Watching ${players} pilot${players === 1 ? '' : 's'}.` : `You are P${slot + 1}.` });
  slotChip.style.cssText = 'margin:0;font-family:monospace;font-size:0.78rem;color:rgba(180,140,255,0.65);letter-spacing:0.12em;';

  // Animated dots so the screen never looks frozen. Pure CSS-free fallback
  // (the gameover overlay already uses inline-styled animations elsewhere).
  const dots = el('div', { parent: card, text: '·  ·  ·' });
  dots.style.cssText = 'margin:0;font-size:1.6rem;letter-spacing:0.5em;color:rgba(184,144,255,0.7);animation:peer-stall-fade 1.2s ease-in-out infinite alternate;';

  const cancel = el('button', { className: 'menu-btn secondary', parent: card, text: 'CANCEL · BACK TO LOBBY' });
  cancel.addEventListener('click', () => { window.location.assign('/duel'); });
}

