export function renderTitle(state: GameState): void {
  // Prague booth kiosk: collapse the whole title/menu surface to the stripped
  // booth lobby. This one gate also closes the post-game loop — anything that
  // would show the title shows the lobby instead.
  if (boothKiosk) { renderBoothLobby(state, boothKiosk); return; }
  clearOverlay();
  const overlay = el('div', { className: 'overlay', parent: root });
  setupOverlayArrowNav(overlay);

  // Warm both leader-ghost cache slots: today's seed (for the daily-mode
  // race + chip) and the global top (for the title attract-loop and
  // non-daily races). Both go into the cache so whichever mode the player
  // chooses on IGNITE has a hot ghost. getActiveSeed isn't usable here —
  // the seed only locks on IGNITE — so we read the stored preference
  // directly to anticipate.
  //
  // Deferred off the page-load critical path: an immediate multi-relay fan-out
  // on first paint reads as beacon-like to network-reputation scanners, and the
  // ghost isn't needed until IGNITE (several seconds out). requestIdle keeps the
  // load itself network-quiet; the cache is warm well before a mode is picked.
  // Same idiom as deferProfileFetch.
  const warmGhostCache = (): void => prefetchTopGhost(getStoredDailyPref() ? todayUTC() : null);
  if (typeof window.requestIdleCallback === 'function') {
    window.requestIdleCallback(warmGhostCache, { timeout: 2500 });
  } else {
    window.setTimeout(warmGhostCache, 1000);
  }

  // Pull skin unlocks the player earned on other devices. Fire-and-forget;
  // returned set has already been merged into local. The settings overlay
  // re-reads localStorage each time it opens so by the time the player
  // navigates there the merged set is visible.
  if (state.session) {
    void syncSkinUnlocksFromNostr(state.session.pubkey).catch(() => undefined);
  }

  // Wordmark image rendered with mix-blend-mode: screen so the baked-in
  // black starfield bg drops out and only the green lettering floats over
  // the cycling wave background. The text is preserved as alt for screen
  // readers and shows if the image fails to load.
  const titleLogo = el('img', { parent: overlay });
  titleLogo.className = 'title-logo';
  (titleLogo as HTMLImageElement).src = '/logo.webp';
  (titleLogo as HTMLImageElement).alt = 'PALLASITE';
  (titleLogo as HTMLImageElement).decoding = 'async';
  // Easter egg: long-press the logo to open the secret music player.
  bindLogoLongPress(titleLogo, () => renderMusicPlayer(state, () => renderTitle(state)));
  const tagline = el('p', { parent: overlay, text: 'SHOOT ROCKS · STACK SATS' });
  tagline.style.cssText = 'font-size:1.2rem;color:var(--hud-yellow);letter-spacing:0.25em;text-shadow:0 0 8px rgba(255,216,74,0.5);margin-top:-12px;';
  el('p', { parent: overlay, text: 'Cosmic arcade · Lightning sats · Nostr leaderboards' });

  renderPoolChip(overlay);

  const sessionPanel = el('div', { className: 'session-panel', parent: overlay });
  renderSessionPanel(sessionPanel, state);

  // Mode picker — campaign / drift / bossrush / arena. Sits above difficulty
  // because it changes the SHAPE of the run; difficulty just tunes within.
  renderModeRow(overlay, state);

  // Difficulty selector
  renderDifficultyRow(overlay);

  // Daily / Free toggle
  renderDailyRow(overlay);

  // Streak chip — only renders when the player has completed at least
  // one daily run. The number is the retention hook; once the player has
  // a streak to protect, the daily run pulls them back tomorrow.
  renderStreakChip(overlay);

  // Today's daily-seed leader — surfaces the standing top score on the
  // current daily seed so the title screen always has a visible "duel of
  // the day" hook. Empty state ("be the first") is itself motivating.
  renderDailyLeaderChip(overlay);

  // Persistent-balance chip — shows accumulated sats banked from prior
  // claims + a WITHDRAW button when balance crosses the threshold. Only
  // renders for signed-in players (anon balances live server-side
  // anyway, but the chip is a signed-in surface).
  renderBalanceChip(overlay, state);

  // Pending-claim recovery — if a previous run's claim failed (signer
  // hiccup, network blip, idle-skip dumped to title before retry), the
  // payload is still on localStorage within the server's 5-min replay
  // window. Surface a one-tap retry banner so the sats aren't orphaned.
  renderPendingClaimBanner(overlay, state);

  const row = el('div', { className: 'menu-row', parent: overlay });
  // IGNITE label and behaviour both pivot on the stored mode: DUEL routes to
  // the /duel lobby instead of starting a solo run, so the button reflects
  // that. Refreshes on every renderTitle (called whenever Mode changes).
  const storedMode = getStoredMode();
  const startLabel = storedMode === 'coop-campaign'
    ? 'CO-OP LOBBY · PRESS ENTER'
    : storedMode === 'deathmatch'
      ? 'DEATHMATCH LOBBY · PRESS ENTER'
    : storedMode === 'duel'
      ? 'ENTER LOBBY · PRESS ENTER'
      : 'IGNITE · PRESS ENTER';
  const startBtn = el('button', { className: 'menu-btn', parent: row, text: startLabel });
  startBtn.addEventListener('click', () => {
    void (async () => {
      void audio.unlockAudio();
      // Multiplayer-backed modes take the dedicated lobby route; everything else stays on the solo
      // path. The lobby reads the same broker the peer arena uses, so no
      // session needs to be created here — that happens inside the lobby
      // (HOST flow generates a session id; JOIN consumes one from the URL).
      const mode = getStoredMode();
      if (mode === 'duel' || mode === 'coop-campaign' || mode === 'deathmatch') {
        window.location.assign(mode === 'coop-campaign' ? '/duel?coop=1' : mode === 'deathmatch' ? '/duel?deathmatch=1' : '/duel');
        return;
      }
      // Fallback path for IGNITE without first typing a name: rather
      // than starting a session-less run that can't publish scores or
      // earn anything, provision an Anonymous guest identity inline.
      // The user can rename later from the title session panel.
      if (!state.session) {
        try {
          // Read whatever the title-screen arcade name picker has
          // currently typed. Falls back to 'Anonymous' for a freshly-
          // mounted picker the user hasn't touched.
          const typed = titleNamePickerGetName?.().trim() ?? '';
          state.session = await auth.createGuestSession(typed || 'Anonymous');
        } catch (err) {
          console.warn('[guest] inline create on IGNITE failed:', err);
        }
      }
      lockInDifficulty(getStoredDifficulty());
      gateBehindOnboarding(() => onStartCb?.());
    })();
  });
  const howBtn = el('button', { className: 'menu-btn secondary', parent: row, text: 'HOW TO PLAY' });
  howBtn.addEventListener('click', () => renderHowToPlay(() => renderTitle(state)));
  const settingsBtn = el('button', { className: 'menu-btn secondary', parent: row, text: 'SETTINGS' });
  settingsBtn.addEventListener('click', () => {
    void audio.unlockAudio();
    renderSettings(() => renderTitle(state));
  });
  // Phone-as-controller — kicks off the pairing UI (QR code) and binds
  // accepted controller inputs into state.keys / state.targetHeading.
  // The host persists across the title→game transition; closing the
  // dialog with "KEEP CONNECTED" leaves the phone in charge.
  const phoneLabel = hasActiveControllerHost() ? '📱 PHONE · PAIRED' : '📱 USE PHONE';
  const phoneBtn = el('button', { className: 'menu-btn secondary', parent: row, text: phoneLabel });
  if (hasActiveControllerHost()) {
    phoneBtn.style.color = '#8cffb4';
    phoneBtn.style.borderColor = 'rgba(140,255,180,0.55)';
  }
  phoneBtn.addEventListener('click', () => {
    void audio.unlockAudio();
    renderControllerHostPairing(state, () => renderTitle(state));
  });
  // Music player — was behind a hidden logo long-press, surfaced as a
  // real button so players can find it without discovering the gesture.
  const musicBtn = el('button', { className: 'menu-btn secondary', parent: row, text: '🎵 MUSIC' });
  musicBtn.addEventListener('click', () => {
    void audio.unlockAudio();
    renderMusicPlayer(state, () => renderTitle(state));
  });
  // Desktop download — web only. A downloaded app shouldn't advertise the
  // download; desktop builds inject __PALLASITE_API_ORIGIN__, so gate on that.
  if (!(globalThis as { __PALLASITE_API_ORIGIN__?: unknown }).__PALLASITE_API_ORIGIN__) {
    const dlBtn = el('button', { className: 'menu-btn secondary', parent: row, text: '⬇ GET THE APP' });
    dlBtn.addEventListener('click', () => renderDownload(() => renderTitle(state)));
  }
  // DUEL used to live here as a separate action button; it now sits in the
  // Mode picker alongside CAMPAIGN / DRIFT / ARENA / SANCTUM so the choice
  // of "what kind of run am I about to start" is on one shelf. Selecting
  // DUEL flips the IGNITE button's label + behaviour above.

  // Defender used to be a big-yellow standalone button here; it now
  // lives in the Mode picker (above) as DEFENDER, same channel as
  // CAMPAIGN / SANCTUM / etc. The `?defender=1` URL flag still works
  // for dev / shareable links and is honoured by main.ts boot.

  // Show local high scores under the start button if any exist. Local entries
  // sometimes carry an eventId (set when the player published this run via the
  // faucet); when they do, the row is clickable and replays in the theatre.
  const selectedBoard: ScoreBoardId = getStoredMode() === 'coop-campaign' ? 'coop-campaign' : 'solo';
  const list = getLocalHighScores(selectedBoard);
  if (list.length > 0) {
    renderLeaderboardBlock(overlay, list, selectedBoard === 'coop-campaign' ? '— LOCAL CO-OP CAMPAIGN —' : '— LOCAL HIGH SCORES —', 5, () => renderTitle(state));
  }

  // Global leaderboard from kind 30762 events on relays. Rendered async so
  // the title screen never blocks on a network round-trip — show a placeholder
  // while it loads, swap in the real list when the relays answer.
  renderGlobalLeaderboard(overlay, state, selectedBoard);

  // Zap-us QR — passers-by / players can send sats anytime, not just after a
  // run. Static LNURL-pay; we never pay out for this.
  renderZapUsQR(overlay, state, { caption: 'ZAP US ⚡' });

  renderLegalFooter(overlay);

  // Keyboard cheatsheet removed — HOW TO PLAY button covers the same content
  // and the duplicate strip cramped the desktop layout against the high scores.
}

// ── Three-screen flow: attract → auth → mission select ──────────────────────
//
// Classic arcade structure. The title used to be a "settings dashboard"
// (logo + tagline + session panel + modes + difficulty + daily + streak +
// balance + pending claim + buttons + leaderboards all on one screen),
// which served the dev fine but read busy for new players. The new flow:
//
//   ATTRACT    Just logo + tagline + rotating panel + huge PLAY + footer.
//              Insert-coin energy — nothing to configure, nothing to learn,
//              one obvious thing to tap. Returning users skip auth and go
//              straight to mission select.
//
//   AUTH       Two-button chooser: SIGN IN WITH NOSTR (existing Signet flow)
//              or PLAY AS GUEST (arcade name picker → local keypair + kind 0
//              metadata + opt-out kind 3 follow of the Pallasite npub).
//
//   MISSION    renderTitle as it stands today — modes, difficulty, daily
//   SELECT     toggle, balance, pending claim, IGNITE, phone pairing,
//              leaderboards. Reached from attract via PLAY (after auth if
//              needed), or directly from game-over via "PLAY AGAIN".
//
// Rotation panels, kind 0 + kind 3 publish, game-over initials drop, and
// the universal claim destination flow are layered on top in follow-up
// commits. This commit is scaffolding only — visual redesign comes later.

/** Top-right utility chip strip on the attract screens. Always shows
 *  a SETTINGS chip. Conditionally shows INSTALL (Android Chrome with
 *  a captured beforeinstallprompt) or a Share-menu hint (iOS Safari).
 *  Once the page is running standalone, the install surfaces go away.
 *  `rerender` is the parent's render fn — called after a dismiss so
 *  the strip re-paints without the hint chip. */
function mountAttractUtilityChips(overlay: HTMLElement, rerender: () => void): void {
  const strip = el('div', { parent: overlay });
  strip.style.cssText = [
    // Respect the iPhone notch / dynamic island safe area. Without this
    // the SETTINGS chip can be obscured by the notch in portrait on
    // newer iPhones — and that's the only way to access settings from
    // the 600bn title.
    'position:absolute', 'top:max(14px, env(safe-area-inset-top))', 'right:14px',
    'display:flex', 'gap:8px', 'flex-wrap:wrap',
    'justify-content:flex-end', 'max-width:60%',
    'z-index:5',
  ].join(';');

  const chipStyle = [
    'font:bold 11px ui-monospace,monospace',
    'letter-spacing:0.16em',
    'padding:6px 12px',
    'background:rgba(20,12,36,0.78)',
    'border:1px solid rgba(255,216,74,0.5)',
    'color:#ffd84a',
    'border-radius:3px',
    'cursor:pointer',
    'text-decoration:none',
  ].join(';');

  // SETTINGS — always. Opens the standard panel; closing returns to
  // whichever attract called us via rerender (the panel restores the
  // overlay so we'd be wiped otherwise).
  const settingsChip = el('button', { parent: strip, text: '⚙ SETTINGS' });
  settingsChip.style.cssText = chipStyle;
  settingsChip.addEventListener('click', () => {
    void audio.unlockAudio();
    renderSettings(rerender);
  });

  // Install / fullscreen surfaces only matter on mobile and only when
  // we're not already in a standalone window.
  if (isMobileViewport() && !isStandalone()) {
    if (canInstallNow()) {
      // Android Chrome path — replay the captured beforeinstallprompt.
      const installChip = el('button', { parent: strip, text: '📲 INSTALL' });
      installChip.style.cssText = chipStyle;
      installChip.style.color = '#8cffb4';
      installChip.style.borderColor = 'rgba(140,255,180,0.55)';
      installChip.addEventListener('click', () => {
        void triggerInstall().then((accepted) => {
          if (accepted) rerender();
        });
      });
    } else if (isIosSafari() && !isInstallHintDismissed()) {
      // iOS Safari can't be triggered programmatically. Surface a
      // dismissable hint that points at the Share menu.
      const iosChip = el('button', { parent: strip, text: '🏠 ADD TO HOME · TAP ⎙' });
      iosChip.style.cssText = chipStyle;
      iosChip.style.color = '#8cffb4';
      iosChip.style.borderColor = 'rgba(140,255,180,0.55)';
      iosChip.title = 'Tap the Share icon in Safari, then "Add to Home Screen" for fullscreen.';
      iosChip.addEventListener('click', () => {
        dismissInstallHint();
        rerender();
      });
    } else if (hasFullscreenAPI()) {
      // Non-installable mobile (e.g. Android Chrome without an install
      // prompt yet, or iOS Chrome). Offer fullscreen as a fallback so
      // there's at least SOMETHING the player can tap for more screen.
      const fsChip = el('button', { parent: strip, text: '⛶ FULLSCREEN' });
      fsChip.style.cssText = chipStyle;
      fsChip.addEventListener('click', () => {
        tryEnterFullscreen();
      });
    }
  }
}

interface EventLobbyConfig {
  enabled: boolean;
  lobbyName: string;
  booth: number;
  boothCount: number;
}

const EVENT_LOBBY_KEY = 'pallasite:eventLobby';
const DEFAULT_EVENT_LOBBY: EventLobbyConfig = {
  enabled: false,
  lobbyName: 'BTC PRAGUE',
  booth: 1,
  boothCount: 2,
};

function normaliseEventLobby(raw: unknown): EventLobbyConfig {
  const obj = raw && typeof raw === 'object' ? raw as Partial<EventLobbyConfig> & { eventName?: string } : {};
  const boothCountRaw = Math.floor(Number(obj.boothCount ?? DEFAULT_EVENT_LOBBY.boothCount));
  const boothCount = Math.max(1, Math.min(12, Number.isFinite(boothCountRaw) ? boothCountRaw : DEFAULT_EVENT_LOBBY.boothCount));
  const boothRaw = Math.floor(Number(obj.booth ?? DEFAULT_EVENT_LOBBY.booth));
  const lobbyName = obj.lobbyName ?? obj.eventName;
  return {
    enabled: obj.enabled === true,
    lobbyName: typeof lobbyName === 'string' && lobbyName.trim() ? lobbyName.trim().slice(0, 32) : DEFAULT_EVENT_LOBBY.lobbyName,
    booth: Math.max(1, Math.min(boothCount, Number.isFinite(boothRaw) ? boothRaw : DEFAULT_EVENT_LOBBY.booth)),
    boothCount,
  };
}

function getEventLobbyConfig(): EventLobbyConfig {
  try {
    const raw = localStorage.getItem(EVENT_LOBBY_KEY);
    if (!raw) return { ...DEFAULT_EVENT_LOBBY };
    return normaliseEventLobby(JSON.parse(raw));
  } catch {
    return { ...DEFAULT_EVENT_LOBBY };
  }
}

function setEventLobbyConfig(next: Partial<EventLobbyConfig>): EventLobbyConfig {
  const cfg = normaliseEventLobby({ ...getEventLobbyConfig(), ...next });
  try { localStorage.setItem(EVENT_LOBBY_KEY, JSON.stringify(cfg)); } catch { /* ignore */ }
  return cfg;
}

function eventLobbyEnabled(): boolean {
  return getEventLobbyConfig().enabled;
}

function eventLobbyConfigForRoute(): EventLobbyConfig {
  const cfg = getEventLobbyConfig();
  try {
    const params = new URLSearchParams(window.location.search);
    const lobbyName = params.get('lobby') ?? params.get('event');
    const booth = params.get('booth') ?? params.get('station');
    const boothCount = params.get('booths') ?? params.get('stations');
    return normaliseEventLobby({
      ...cfg,
      ...(lobbyName ? { lobbyName } : {}),
      ...(booth ? { booth } : {}),
      ...(boothCount ? { boothCount } : {}),
    });
  } catch {
    return cfg;
  }
}

