/** Render an avatar + name chip for a player identity into `parent`, repainting
 *  when the kind-0 profile lands. Reused on the booth join wizard's control-pick
 *  step and (later) the HUD / game-over. */
function renderIdentityChip(parent: HTMLElement, pubkey: string, fallbackName: string, label: string, colour: string): void {
  const chip = el('div', { parent });
  chip.style.cssText = 'display:flex;align-items:center;gap:10px;';
  let profile = getCachedProfile(pubkey);
  const paint = (): void => {
    chip.innerHTML = '';
    if (profile?.picture) {
      const img = document.createElement('img');
      img.src = profile.picture;
      img.alt = '';
      img.style.cssText = `width:40px;height:40px;border-radius:50%;border:2px solid ${colour};object-fit:cover;`;
      img.onerror = () => { img.style.display = 'none'; };
      chip.appendChild(img);
    }
    // No cached profile yet: prefer an explicit fallback name (e.g. a guest's
    // chosen name), else a short pubkey — NOT the literal "guest", which
    // mislabels a real signed-in identity (a My Signet natural-person carries no
    // displayName) until its kind-0 profile lands and we repaint with bestName.
    const name = profile ? bestName(profile, pubkey) : (fallbackName.trim() || bestName(null, pubkey));
    const t = document.createElement('div');
    t.style.cssText = 'text-align:left;';
    t.innerHTML = `<div style="font-size:0.62rem;letter-spacing:0.2em;color:${colour};">${escapeHtml(label)}</div>`
      + `<div style="font-size:0.92rem;color:#fff;font-weight:bold;">${escapeHtml(name)}</div>`;
    chip.appendChild(t);
  };
  paint();
  if (!profile) deferProfileFetch(pubkey, p => { profile = p; paint(); });
}

function deferProfileFetch(pubkey: string, onProfile: (profile: NostrProfile) => void): void {
  const refresh = () => {
    void fetchProfile(pubkey, { timeoutMs: 2500 }).then(p => { if (p) onProfile(p); });
  };
  if (typeof window.requestIdleCallback === 'function') {
    window.requestIdleCallback(refresh, { timeout: 3000 });
  } else {
    window.setTimeout(refresh, 600);
  }
}

// ── Booth setup wizard (?p1/?p2) ──────────────────────────────────────────────
// Gamepad-first walk-up flow: press Ⓐ to join (how many pads press Ⓐ decides 1P
// vs 2P), then each joined pilot signs in (Nostr or guest) and picks their own
// flight scheme, then the run starts (solo, or local couch for two). The wizard
// owns the gamepads for its whole lifetime: it suppresses the main loop's pad
// routing and runs ONE rAF poll that — on the join screen — edge-detects Ⓐ/Start
// per pad, and — on a per-pilot setup step — drives just that pilot's pad through
// the menus via driveMenuFromPad. LINK BOOTHS (cross-booth) stays a separate path.
//
// A gamepad press is not a browser user-gesture, so audio.unlockAudio() /
// tryEnterFullscreen() are best-effort here — reliable via a real tap (touch
// booth) or the operator's initial page-load click. Launch the booth in kiosk
// fullscreen and give it one operator tap to unlock audio.

/** The three pad flight schemes, shared by the per-pilot control pick. */
const PAD_SCHEME_OPTS: ReadonlyArray<{ value: PadFlightMode; label: string; hint: string }> = [
  { value: 'flydirect', label: 'POINT & FLY',    hint: 'Pickup-and-go — push the left stick to aim and fly together' },
  { value: 'throttle',  label: 'AIM + THROTTLE', hint: 'Left stick aims, right trigger throttles — hold a firing line' },
  { value: 'classic',   label: 'CLASSIC',        hint: 'Arcade — d-pad turns, right trigger (or d-pad up) thrusts' },
];

interface BoothPilot { padIndex: number; slot: number; session: SignetSession | null; }

interface BoothWizard {
  active: boolean;
  booth: number;
  mode: 'join' | 'nav';
  /** gamepad.index of the pad driving the menus during a per-pilot setup step. */
  activePad: number | null;
  nav: MenuNavState;
  /** Per-pad (gamepad.index) edge memory for the join screen's Ⓐ / Start. */
  joinEdge: Map<number, { a: boolean; start: boolean }>;
  /** Per-pad edge memory for the operator settings cheat (see feedBoothCheat). */
  cheat: Map<number, { lastDir: 'up' | 'down' | 'left' | 'right' | null; prevY: boolean; seq: string[] }>;
  pilots: BoothPilot[];
  raf: number | null;
}

let boothWizard: BoothWizard | null = null;

/** True once a booth pilot has signed in (guest or Nostr) via the join wizard.
 *  main.ts's boot-time session restore reads this so a slow tryRestore() of the
 *  device's persisted personal session can't overwrite the pilot's chosen
 *  identity — which made a walk-up's run score under whoever last signed in on
 *  the device (e.g. a guest "DAZ" landing as the operator's TheCryptoDonkey). */
let boothPilotSessionClaimed = false;
export function boothPilotSessionWasClaimed(): boolean { return boothPilotSessionClaimed; }

function stopBoothWizard(): void {
  if (!boothWizard) return;
  if (boothWizard.raf !== null) cancelAnimationFrame(boothWizard.raf);
  boothWizard.active = false;
  boothWizard = null;
  setPadInputSuppressed(false);   // hand the pads back to the in-game loop
}

// One-time "TAP TO START" gate state. A gamepad press is NOT a browser
// user-gesture, so a pad-driven booth kiosk can't unlock its AudioContext and
// starts SILENT until a real tap. The gate forces one real gesture per page
// session; once primed, later cohorts skip straight to the join wizard.
let boothAudioPrimed = false;
let boothGateRaf: number | null = null;
let boothGateKeyup: ((e: KeyboardEvent) => void) | null = null;
function stopBoothGate(): void {
  if (boothGateRaf !== null) { cancelAnimationFrame(boothGateRaf); boothGateRaf = null; }
  if (boothGateKeyup) { window.removeEventListener('keyup', boothGateKeyup, true); boothGateKeyup = null; }
}

/** Entry for `?p1`/`?p2`. (Re)starts the wizard on a clean cohort: each new
 *  group joins + signs in from scratch (replacing the old SIGN OUT hand-over).
 *  state.session is left as-is (a redirect sign-in may have just set it) — the
 *  per-pilot auth step always overwrites it with this cohort's choice. */
export function renderBoothLobby(state: GameState, booth: number): void {
  stopBoothWizard();
  stopBoothGate();
  state.coopIdentity2 = null;
  clearPadFlightModeBySlot();
  clearBoothPadSlotBinding();
  // Booth default is CLASSIC (arcade rotate-and-thrust) — the most familiar
  // scheme for walk-ups and what the on-screen legend describes. Each pilot's
  // join-wizard picker still falls back to this, so they can switch per-slot.
  setPadFlightMode('classic');
  setPadAutoThrust(false);

  // A booth kiosk is gamepad-driven, but a gamepad press is NOT a browser
  // user-gesture — so audio.unlockAudio() from the pad flow is rejected and the
  // kiosk starts silent (no music/SFX) until a real tap. Gate the FIRST entry of
  // the page session behind a real "TAP TO START" gesture that unlocks the
  // AudioContext + enters fullscreen; once primed, later cohorts skip it.
  if (!boothAudioPrimed) {
    renderBoothStartGate(state, booth);
    return;
  }
  startBoothJoinWizard(state, booth);
}

/** The press-Ⓐ-to-join wizard proper, split out of renderBoothLobby so the
 *  one-time audio-unlock gate can run ahead of it. */
function startBoothJoinWizard(state: GameState, booth: number): void {
  // Booth music revival. The booth replaces the title screen with this lobby and
  // loops back here after every run — but a run ends in phase 'gameover', whose
  // resolved track is the one-shot `hull-breached` sting (loop:false). If we
  // re-enter the idle lobby still in that phase, music resolves to a sting that
  // already finished → silence ("not playing again"). Snap the phase back to
  // 'title' (the looping idle pool) and invalidate the track memo so the game
  // loop's next musicSetTrackForState tick crossfades the idle bed back in.
  state.phase = 'title';
  try { void audio.unlockAudio(); } catch { /* best-effort: already unlocked */ }
  musicForceRefresh();

  const w: BoothWizard = {
    active: true, booth, mode: 'join', activePad: null,
    nav: { menuDir: null, menuA: false, menuB: false },
    joinEdge: new Map(), cheat: new Map(), pilots: [], raf: null,
  };
  boothWizard = w;
  setPadInputSuppressed(true);   // the wizard owns the pads now
  const tick = (): void => {
    if (!w.active || boothWizard !== w) return;
    pollBoothWizard(state, w);
    w.raf = requestAnimationFrame(tick);
  };
  w.raf = requestAnimationFrame(tick);
  renderBoothJoin(state, booth);
}

/** One-time audio-unlock gate. A REAL trusted gesture (tap / click / any key)
 *  unlocks audio + fullscreen, then drops into the join wizard. A gamepad button
 *  is a SAFETY NET: it proceeds WITHOUT audio (a pad can't unlock the context)
 *  so a pad-only kiosk is never stuck — just silent until someone taps. The pad
 *  net is edge-detected off the buttons already held, so the Ⓐ that navigated
 *  here doesn't skip the gate instantly. */
function renderBoothStartGate(state: GameState, booth: number): void {
  clearOverlay();
  const overlay = el('div', { className: 'overlay', parent: root });
  setupOverlayArrowNav(overlay);
  document.body.dataset.surface = 'event';

  const titleLogo = el('img', { parent: overlay });
  titleLogo.className = 'title-logo';
  (titleLogo as HTMLImageElement).src = '/logo.webp';
  (titleLogo as HTMLImageElement).alt = 'PALLASITE';
  (titleLogo as HTMLImageElement).decoding = 'async';

  const kicker = el('p', { parent: overlay, text: `BTC PRAGUE · BOOTH ${booth}` });
  kicker.style.cssText = 'font-size:1rem;color:#8cffb4;letter-spacing:0.28em;text-shadow:0 0 8px rgba(140,255,180,0.4);margin:-12px 0 0;';

  const btn = el('button', { className: 'menu-btn', parent: overlay, text: '▶ TAP TO START' }) as HTMLButtonElement;
  btn.style.cssText += 'font-size:1.7rem;padding:24px 60px;letter-spacing:0.2em;margin:26px auto;display:block;background:rgba(255,216,74,0.18);border-color:#ffd84a;color:#ffd84a;';

  const hint = el('p', { parent: overlay, text: 'Tap the screen once to turn on sound — then grab a pad and press Ⓐ to play.' });
  hint.style.cssText = 'font-size:0.86rem;color:rgba(220,210,255,0.76);letter-spacing:0.06em;text-align:center;max-width:520px;line-height:1.5;margin:0;';

  let done = false;
  let allReleased = false;
  const proceed = (withAudio: boolean): void => {
    if (done) return;
    done = true;
    boothAudioPrimed = true;
    stopBoothGate();
    if (withAudio) {
      try { void audio.unlockAudio(); } catch { /* best-effort */ }
      try { tryEnterFullscreen(); } catch { /* best-effort (e.g. headless / blocked) */ }
    }
    startBoothJoinWizard(state, booth);
  };

  // Real gesture → sound on.
  onTap(btn, () => proceed(true));
  boothGateKeyup = (e: KeyboardEvent): void => { if (e.isTrusted) proceed(true); };
  window.addEventListener('keyup', boothGateKeyup, true);
  setTimeout(() => tryFocusVisible(btn), 0);

  // Gamepad safety net — proceed silently on a FRESH press (all buttons released
  // first, then one goes down).
  const padTick = (): void => {
    if (done) return;
    let anyDown = false;
    const pads = (typeof navigator !== 'undefined' && navigator.getGamepads) ? navigator.getGamepads() : [];
    for (const p of pads) {
      if (!p || !p.connected) continue;
      for (let i = 0; i < p.buttons.length; i++) { if (padButtonDown(p, i)) { anyDown = true; break; } }
      if (anyDown) break;
    }
    if (!allReleased) { if (!anyDown) allReleased = true; }
    else if (anyDown) { proceed(false); return; }
    boothGateRaf = requestAnimationFrame(padTick);
  };
  boothGateRaf = requestAnimationFrame(padTick);
}

/** One rAF of wizard pad input. Join mode: a pad's Ⓐ joins the next free slot
 *  (or, if that pad already joined, begins); Start (9) begins. Nav mode: only the
 *  active pilot's pad walks the current overlay (sign-in / scheme pick). */
function pollBoothWizard(state: GameState, w: BoothWizard): void {
  if (typeof navigator === 'undefined' || typeof navigator.getGamepads !== 'function') return;
  const all = navigator.getGamepads();
  if (!all) return;
  if (w.mode === 'join') {
    for (const pad of all) {
      if (w.mode !== 'join') break;          // a join/begin flipped us to nav
      if (!pad || !pad.connected) continue;
      let edge = w.joinEdge.get(pad.index);
      if (!edge) { edge = { a: false, start: false }; w.joinEdge.set(pad.index, edge); }
      const a = padButtonDown(pad, 0);
      const start = padButtonDown(pad, 9);
      if (a && !edge.a) onBoothJoinPress(state, w, pad.index);
      if (start && !edge.start && w.pilots.length > 0) beginBoothSetup(state, w);
      edge.a = a; edge.start = start;
      // Operator settings cheat: ▼ ▶ ◀ ◀ Ⓨ on any pad opens Settings.
      if (feedBoothCheat(state, w, pad)) return;
    }
    return;
  }
  if (w.activePad === null) return;
  const pad = all[w.activePad];
  if (pad && pad.connected) driveMenuFromPad(pad, w.nav);
}

/** Ⓐ on the join screen: an unjoined pad takes the next free slot; a pad that has
 *  already joined begins setup — so a lone pilot just taps Ⓐ twice to go solo. */
function onBoothJoinPress(state: GameState, w: BoothWizard, padIndex: number): void {
  if (w.pilots.some((p) => p.padIndex === padIndex)) { beginBoothSetup(state, w); return; }
  if (w.pilots.length >= 2) return;            // booth is two-up
  void audio.unlockAudio();
  w.pilots.push({ padIndex, slot: w.pilots.length, session: null });
  renderBoothJoin(state, w.booth);
}

// ── Booth operator settings cheat ───────────────────────────────────────────
// A booth kiosk has no keyboard, so Settings is otherwise unreachable once the
// join wizard owns the pads. On the join menu, the sequence ▼ ▶ ◀ ◀ Ⓨ on any
// pad opens Settings; the wizard's nav mode then drives the overlay (Ⓑ = back).
const BOOTH_SETTINGS_CHEAT: ReadonlyArray<string> = ['down', 'right', 'left', 'left', 'Y'];

/** Combined stick + d-pad direction, using the same 0.55 threshold as
 *  driveMenuFromPad so the cheat feels like normal menu nav. */
function padMenuDir(pad: Gamepad): 'up' | 'down' | 'left' | 'right' | null {
  const dx = (pad.axes[0] ?? 0) + (padButtonDown(pad, 15) ? 1 : 0) - (padButtonDown(pad, 14) ? 1 : 0);
  const dy = (pad.axes[1] ?? 0) + (padButtonDown(pad, 13) ? 1 : 0) - (padButtonDown(pad, 12) ? 1 : 0);
  if (Math.abs(dx) <= 0.55 && Math.abs(dy) <= 0.55) return null;
  return Math.abs(dx) > Math.abs(dy) ? (dx > 0 ? 'right' : 'left') : (dy > 0 ? 'down' : 'up');
}

/** Feed one pad's join-screen input to the settings cheat. Records a token on
 *  each fresh directional press (so "left, left" needs a release between) and on
 *  each Ⓨ rising edge, keeping a rolling window. Returns true when the full
 *  sequence just completed (and Settings was opened). */
function feedBoothCheat(state: GameState, w: BoothWizard, pad: Gamepad): boolean {
  let cs = w.cheat.get(pad.index);
  if (!cs) { cs = { lastDir: null, prevY: false, seq: [] }; w.cheat.set(pad.index, cs); }
  const push = (tok: string): boolean => {
    cs!.seq.push(tok);
    if (cs!.seq.length > BOOTH_SETTINGS_CHEAT.length) cs!.seq.shift();
    return cs!.seq.length === BOOTH_SETTINGS_CHEAT.length
      && cs!.seq.every((t, i) => t === BOOTH_SETTINGS_CHEAT[i]);
  };
  let matched = false;
  const dir = padMenuDir(pad);
  if (dir && dir !== cs.lastDir && push(dir)) matched = true;
  cs.lastDir = dir;
  const y = padButtonDown(pad, 3);
  if (y && !cs.prevY && push('Y')) matched = true;
  cs.prevY = y;
  if (matched) { openBoothSettings(state, w, pad.index); return true; }
  return false;
}

/** Open Settings from the booth menu, reusing the wizard's nav mode so the same
 *  pad walks the overlay. Ⓑ (→ Escape → onBack) returns to the join menu. */
function openBoothSettings(state: GameState, w: BoothWizard, padIndex: number): void {
  w.cheat.clear();
  w.mode = 'nav';
  w.activePad = padIndex;
  w.nav = { menuDir: null, menuA: false, menuB: false };
  renderSettings(() => {
    if (boothWizard !== w || !w.active) return;
    w.mode = 'join';
    w.activePad = null;
    w.nav = { menuDir: null, menuA: false, menuB: false };
    w.cheat.clear();
    renderBoothJoin(state, w.booth);
  });
}

/** One-line control legend for the booth's CLASSIC pad scheme. Shown on the
 *  join lobby and the pause menu so a walk-up always knows the mapping without
 *  hunting through settings. Mirrors DEFAULT_BINDINGS (fire Ⓐ/LT, thrust RT,
 *  shield Ⓑ/RB, hyperspace Ⓧ/LB) and the classic d-pad rotate cluster. */
function renderBoothControlsLegend(parent: HTMLElement): HTMLElement {
  const legend = el('p', { parent, text: '🎮  D-pad ◀ ▶ turn  ·  RT (or D-pad ▲) thrust  ·  Ⓐ fire  ·  Ⓑ shield  ·  Ⓧ hyperspace  ·  right stick aims + auto-fires' });
  legend.style.cssText = 'font-size:0.74rem;color:rgba(140,255,180,0.66);letter-spacing:0.05em;text-align:center;margin:14px auto 0;max-width:660px;line-height:1.6;';
  return legend;
}

function renderBoothJoin(state: GameState, booth: number): void {
  const w = boothWizard;
  clearOverlay();
  const overlay = el('div', { className: 'overlay', parent: root });
  setupOverlayArrowNav(overlay);
  document.body.dataset.surface = 'event';

  const titleLogo = el('img', { parent: overlay });
  titleLogo.className = 'title-logo';
  (titleLogo as HTMLImageElement).src = '/logo.webp';
  (titleLogo as HTMLImageElement).alt = 'PALLASITE';
  (titleLogo as HTMLImageElement).decoding = 'async';

  const kicker = el('p', { parent: overlay, text: `BTC PRAGUE · BOOTH ${booth}` });
  kicker.style.cssText = 'font-size:1rem;color:#8cffb4;letter-spacing:0.28em;text-shadow:0 0 8px rgba(140,255,180,0.4);margin:-12px 0 0;';
  const intro = el('p', { parent: overlay, text: 'Grab a pad and press Ⓐ to drop in. Two pilots welcome — one screen, one campaign.' });
  intro.style.cssText = 'font-size:0.88rem;color:rgba(220,210,255,0.76);letter-spacing:0.08em;text-align:center;max-width:520px;line-height:1.45;margin:0;';

  const joined = w?.pilots.length ?? 0;

  // Two slot cards. Each is clickable too (touch booths + headless tests): a
  // click joins that slot exactly as a pad's Ⓐ does.
  const cards = el('div', { parent: overlay });
  cards.style.cssText = 'display:flex;gap:18px;justify-content:center;flex-wrap:wrap;margin:18px 0 6px;';
  for (let slot = 0; slot < 2; slot++) {
    const taken = slot < joined;
    const colour = PLAYER_COLOURS[slot];
    const card = el('button', { parent: cards }) as HTMLButtonElement;
    card.style.cssText = [
      'display:flex', 'flex-direction:column', 'align-items:center', 'justify-content:center', 'gap:8px',
      'width:min(240px,42vw)', 'padding:26px 18px', 'border-radius:10px', 'cursor:pointer',
      'background:' + (taken ? 'rgba(40,40,60,0.55)' : 'rgba(20,12,36,0.72)'),
      'border:2.5px solid ' + (taken ? colour : 'rgba(255,216,74,0.45)'),
      taken ? `box-shadow:0 0 22px ${colour}55` : '',
    ].filter(Boolean).join(';');
    el('span', { parent: card, text: `PLAYER ${slot + 1}` })
      .style.cssText = `font-family:'VT323',ui-monospace,monospace;font-size:1.5rem;letter-spacing:0.18em;color:${taken ? colour : 'rgba(220,210,255,0.85)'};`;
    el('span', { parent: card, text: taken ? '✓ READY' : 'PRESS Ⓐ' })
      .style.cssText = `font-family:'VT323',ui-monospace,monospace;font-size:2rem;letter-spacing:0.16em;color:${taken ? colour : '#ffd84a'};`;
    card.addEventListener('click', () => {
      const cw = boothWizard; if (!cw || cw.mode !== 'join') return;
      void audio.unlockAudio();
      if (slot < cw.pilots.length) { beginBoothSetup(state, cw); return; }
      if (slot === cw.pilots.length) { cw.pilots.push({ padIndex: -1 - slot, slot, session: null }); renderBoothJoin(state, booth); }
    });
  }

  // START — once at least one pilot has joined. A joined pad's Ⓐ (or Start) does
  // the same; this is the focusable click/touch equivalent.
  const startRow = el('div', { className: 'menu-row', parent: overlay });
  if (joined > 0) {
    const startBtn = el('button', { className: 'menu-btn', parent: startRow, text: joined > 1 ? '▶ START · 2 PLAYERS' : '▶ START · SOLO' }) as HTMLButtonElement;
    startBtn.style.cssText += 'font-size:1.1rem;padding:12px 36px;letter-spacing:0.18em;background:rgba(255,216,74,0.18);border-color:#ffd84a;color:#ffd84a;';
    startBtn.addEventListener('click', () => { const cw = boothWizard; if (cw && cw.mode === 'join') beginBoothSetup(state, cw); });
    setTimeout(() => tryFocusVisible(startBtn), 0);
  } else {
    el('p', { parent: startRow, text: 'Waiting for a pilot…' })
      .style.cssText = 'font-size:0.8rem;color:rgba(180,140,255,0.6);letter-spacing:0.14em;';
  }

  // Control legend — booth default is CLASSIC arcade (each pilot can still
  // switch scheme in the next step). Shared with the pause menu.
  renderBoothControlsLegend(overlay);

  // LINK BOOTHS — a separate thing: cross-booth networked co-op. Kept small.
  const link = el('button', { parent: overlay, text: '🔗 LINK BOOTHS' });
  link.style.cssText = 'margin-top:14px;background:rgba(91,208,255,0.12);border:1px solid rgba(91,208,255,0.5);color:#5bd0ff;font:0.74rem ui-monospace,monospace;letter-spacing:0.14em;padding:7px 16px;border-radius:6px;cursor:pointer;';
  link.addEventListener('click', () => startLinkedBooth(booth));

  // Zap-us QR — persistent "send us sats" surface, same as attract / title.
  renderZapUsQR(overlay, state, { caption: 'ZAP US ⚡' });

  // Operator escape — long-press the logo to drop the kiosk flag → full menu.
  bindLogoLongPress(titleLogo, () => { stopBoothWizard(); window.location.assign('/'); });
}

/** A pilot pressed begin → run each joined pilot through sign-in, then a control
 *  pick, in order; then start the run. */
function beginBoothSetup(state: GameState, w: BoothWizard): void {
  if (w.pilots.length === 0) return;
  void audio.unlockAudio();
  tryEnterFullscreen();
  setupBoothPilot(state, w, 0);
}

function setupBoothPilot(state: GameState, w: BoothWizard, i: number): void {
  if (i >= w.pilots.length) { startBoothRun(w); return; }
  const pilot = w.pilots[i];
  armBoothNav(w, pilot);
  const n = i + 1;
  // Sign in — Nostr or guest. P1 → state.session; P2 → state.coopIdentity2 (the
  // existing couch-in-place second-identity field).
  renderAuth(state, () => renderBoothSchemePick(state, w, i), {
    heading: `PLAYER ${n} — SIGN IN`,
    sub: w.pilots.length > 1
      ? `Player ${n} signs in with their own Nostr identity (or guest).`
      : 'Sign in with Nostr to carry your name + zaps everywhere — or play as a guest.',
    // Shared booth device: a guest sign-in here is a NEW walk-up each time, so
    // mint a fresh named identity rather than inheriting the stored record.
    freshGuest: true,
    onResolved: (s) => {
      // Lock out the boot-time restore: once a pilot explicitly signs in here,
      // the device's persisted personal session must not clobber this identity.
      boothPilotSessionClaimed = true;
      pilot.session = s;
      if (i === 0) {
        state.session = s;
        state.profile = getCachedProfile(s.pubkey);
        if (!state.profile) void fetchProfile(s.pubkey).then((p) => { if (p && state.session?.pubkey === s.pubkey) state.profile = p; });
      } else {
        state.coopIdentity2 = { pubkey: s.pubkey, displayName: s.displayName ?? '', profile: getCachedProfile(s.pubkey), session: s };
        if (!state.coopIdentity2.profile) void fetchProfile(s.pubkey).then((p) => { if (p && state.coopIdentity2) state.coopIdentity2.profile = p; });
      }
    },
  });
}

/** Hand the menus to one pilot's pad, debouncing the Ⓐ that's likely still held
 *  from the previous step so it doesn't instantly confirm the first focusable. */
function armBoothNav(w: BoothWizard, pilot: BoothPilot): void {
  w.mode = 'nav';
  w.activePad = pilot.padIndex >= 0 ? pilot.padIndex : null;
  w.nav = { menuDir: null, menuA: true, menuB: true };
}

function renderBoothSchemePick(state: GameState, w: BoothWizard, i: number): void {
  const pilot = w.pilots[i];
  armBoothNav(w, pilot);   // re-arm: the Ⓐ that confirmed sign-in is likely held
  clearOverlay();
  const overlay = el('div', { className: 'overlay', parent: root });
  setupOverlayArrowNav(overlay);
  const n = i + 1;
  el('h2', { parent: overlay, text: `PLAYER ${n} — CONTROLS` });

  if (pilot.session) {
    const who = el('div', { parent: overlay });
    who.style.cssText = 'display:flex;justify-content:center;margin:2px 0 12px;';
    renderIdentityChip(who, pilot.session.pubkey, pilot.session.displayName ?? '', `PLAYER ${n}`, PLAYER_COLOURS[pilot.slot]);
  }

  el('p', { parent: overlay, text: 'Pick how your pad flies. The right stick aims + auto-fires in every mode.' })
    .style.cssText = 'font-size:0.84rem;color:rgba(220,210,255,0.72);margin:0 auto 14px;max-width:520px;text-align:center;line-height:1.5;';

  const panel = el('div', { parent: overlay });
  panel.style.cssText = 'display:flex;gap:12px;align-items:stretch;justify-content:center;flex-wrap:wrap;';
  const cur = getPadFlightModeForSlot(pilot.slot);
  let focusBtn: HTMLButtonElement | null = null;
  for (const opt of PAD_SCHEME_OPTS) {
    const on = opt.value === cur;
    const b = el('button', { parent: panel }) as HTMLButtonElement;
    b.style.cssText = [
      'display:flex', 'flex-direction:column', 'gap:6px', 'width:min(220px,40vw)', 'padding:14px 16px', 'text-align:left',
      'background:' + (on ? 'rgba(88,255,88,0.16)' : 'rgba(20,12,36,0.72)'),
      'border:2px solid ' + (on ? '#58ff58' : 'rgba(180,140,255,0.4)'),
      'border-radius:8px', 'cursor:pointer',
    ].join(';');
    el('span', { parent: b, text: opt.label }).style.cssText = "font-family:'VT323',ui-monospace,monospace;font-size:1.3rem;letter-spacing:0.14em;color:#ffd84a;";
    el('span', { parent: b, text: opt.hint }).style.cssText = 'font-size:0.74rem;color:rgba(220,210,255,0.7);line-height:1.4;';
    b.addEventListener('click', () => { setPadFlightModeForSlot(pilot.slot, opt.value); setupBoothPilot(state, w, i + 1); });
    if (on) focusBtn = b;
  }
  if (focusBtn) { const fb = focusBtn; setTimeout(() => tryFocusVisible(fb), 0); }

  el('p', { parent: overlay, text: 'Press Ⓐ on your choice.' })
    .style.cssText = 'font-size:0.74rem;color:rgba(180,140,255,0.6);letter-spacing:0.14em;margin:14px 0 0;text-align:center;';
}

function startBoothRun(w: BoothWizard): void {
  const twoUp = w.pilots.length > 1;
  // Bind each real pad (by gamepad.index) to its slot so join order = P1 / P2.
  setBoothPadSlotBinding(w.pilots.filter((p) => p.padIndex >= 0).map((p) => ({ slot: p.slot, padIndex: p.padIndex })));
  stopBoothWizard();   // re-enable the in-game pad loop
  setStoredMode('campaign');
  setStoredDailyPref(false);
  lockInDifficulty(getStoredDifficulty());
  gateBehindOnboarding(() => { if (twoUp) startCouchInPlace(); else onStartCb?.(); });
}

/** LINK BOOTHS — cross-booth networked co-op (a separate path from the local
 *  press-Ⓐ flow). One pilot per booth by default; ?pilots=N,M opts up to 2 each.
 *  Booth 1 → slot 0, Booth 2 → its offset; each booth owns its slot region so no
 *  slot is ever unowned. Rollback on by default; ?rollback=0 falls back to
 *  lockstep. Built directly because coop-campaign hard-codes 2 players. */
function startLinkedBooth(booth: number): void {
  void audio.unlockAudio();
  tryEnterFullscreen();
  const q = new URLSearchParams(window.location.search);
  const link = (q.get('link') || '').replace(/[^a-z0-9]/gi, '').slice(0, 32) || 'praguebooths';
  const counts = (q.get('pilots') || '1,1').split(',').map((nn) => Math.max(1, Math.min(2, parseInt(nn, 10) || 1)));
  const b1 = counts[0] ?? 1, b2 = counts[1] ?? 1;
  const offset = booth === 1 ? 0 : b1;
  const myCount = booth === 1 ? b1 : b2;
  const owned = Array.from({ length: myCount }, (_, i) => offset + i).join(',');
  const params = new URLSearchParams({
    peer: buildBrokerPeerUrl(link),
    session: link,
    slot: String(offset),
    localSlots: owned,
    players: String(b1 + b2),
    mode: 'coop-campaign',
    rollback: q.get('rollback') === '0' ? '0' : '1',
  });
  stopBoothWizard();
  window.location.assign(`${window.location.origin}/?${params.toString()}&p${booth}=1`);
}

export function renderAttract(state: GameState): void {
  if (boothKiosk) { renderBoothLobby(state, boothKiosk); return; }
  // 600bn flavour gets its own bespoke attract screen — sacred number
  // wordmark, single PLAY to drop straight into the Sanctum, no auth
  // step in the way (claim flow at game-over handles sign-in if needed).
  if (getFlavour() === '600bn') {
    renderSanctumAttract(state);
    return;
  }
  if (eventLobbyEnabled()) {
    renderEventLobby(state);
    return;
  }
  clearOverlay();
  const overlay = el('div', { className: 'overlay', parent: root });
  setupOverlayArrowNav(overlay);

  // Top utility chip strip — SETTINGS always, INSTALL when prompt
  // available (Android Chrome), iOS Safari Share-menu hint when not
  // already standalone. Positioned absolute so it doesn't disturb the
  // logo/PLAY centring; only renders on attract because that's where
  // first-time visitors land.
  mountAttractUtilityChips(overlay, () => renderAttract(state));

  // Logo — same wordmark as the previous title.
  const titleLogo = el('img', { parent: overlay });
  titleLogo.className = 'title-logo';
  (titleLogo as HTMLImageElement).src = '/logo.webp';
  (titleLogo as HTMLImageElement).alt = 'PALLASITE';
  (titleLogo as HTMLImageElement).decoding = 'async';
  bindLogoLongPress(titleLogo, () => renderMusicPlayer(state, () => renderAttract(state)));

  const tagline = el('p', { parent: overlay, text: 'SHOOT ROCKS · STACK SATS' });
  tagline.style.cssText = 'font-size:1.2rem;color:var(--hud-yellow);letter-spacing:0.25em;text-shadow:0 0 8px rgba(255,216,74,0.5);margin-top:-12px;';
  el('p', { parent: overlay, text: 'Cosmic arcade · Lightning sats · Nostr leaderboards' });

  // Rotating attract panel — three contents cycle every few seconds:
  //   GLOBAL HIGH SCORES TOP 5   (8s)  — live-updating leaderboard
  //   TOP RUN HIGHLIGHT           (8s) — placeholder for replay
  //                                      autoplay; full live render is
  //                                      a follow-up. Static "top run"
  //                                      stat panel for now.
  //   CREDITS                     (5s) — handcrafted by + zaps tip
  // 300ms crossfade between panels via opacity transition.
  //
  // Each render is fire-and-forget: it mounts a subtree into the panel
  // and tears down on next rotation tick (innerHTML='' is enough since
  // none of the panels open network sockets except the high-scores
  // panel, which checks container.isConnected for self-teardown).
  const attractPanel = el('div', { parent: overlay });
  attractPanel.style.cssText = 'min-height:240px;margin:24px auto;max-width:760px;width:100%;display:flex;align-items:center;justify-content:center;transition:opacity 300ms ease;';
  attractPanel.dataset.attractPanel = '1';

  type AttractPhase = 'scores' | 'replay' | 'credits';
  const PHASE_DURATIONS: Record<AttractPhase, number> = {
    scores: 8000,
    replay: 8000,
    credits: 5000,
  };
  const PHASE_ORDER: readonly AttractPhase[] = ['scores', 'replay', 'credits'];
  let phaseIdx = 0;
  let phaseTimer: number | null = null;

  const mountPhase = (phase: AttractPhase): void => {
    attractPanel.innerHTML = '';
    if (phase === 'scores') {
      // Wrap renderGlobalLeaderboard so we can scope the title to a
      // shorter ATTRACT-style label rather than the full "GLOBAL HIGH
      // SCORES" the mission-select uses.
      const wrap = el('div', { parent: attractPanel });
      wrap.style.cssText = 'width:100%;max-width:560px;text-align:center;';
      renderGlobalLeaderboard(wrap, state, 'solo');
    } else if (phase === 'replay') {
      // v1 placeholder — full live-frame autoplay of a top-zapped run
      // is the next commit. For now show a tasteful "highlight reel
      // loading" stand-in that doesn't promise more than we deliver.
      const wrap = el('div', { parent: attractPanel });
      wrap.style.cssText = 'width:100%;max-width:560px;text-align:center;display:flex;flex-direction:column;gap:8px;align-items:center;';
      const head = el('p', { parent: wrap, text: '⚡ TOP RUN HIGHLIGHTS' });
      head.style.cssText = 'font-size:0.95rem;color:#ffd84a;letter-spacing:0.18em;margin:0;';
      const body = el('p', { parent: wrap, text: 'Autoplay coming soon — open the WATCH page to see live runs and replay-worthy clips from across the relay set.' });
      body.style.cssText = 'font-size:0.82rem;color:rgba(220,210,255,0.65);max-width:480px;line-height:1.5;margin:0;';
      const watchBtn = el('a', { parent: wrap, text: 'OPEN WATCH PAGE ▶' }) as HTMLAnchorElement;
      watchBtn.href = 'https://watch.pallasite.app/';
      watchBtn.target = '_blank';
      watchBtn.rel = 'noopener';
      watchBtn.style.cssText = 'font-size:0.78rem;letter-spacing:0.16em;color:#8cffb4;text-decoration:none;border:1px solid rgba(140,255,180,0.55);padding:4px 14px;border-radius:3px;background:rgba(140,255,180,0.06);margin-top:4px;';
    } else {
      // Credits — minimal. Names + zap pointer; sources from
      // existing credits.ts module if there's more later, but for
      // attract a tight three-line block reads better.
      const wrap = el('div', { parent: attractPanel });
      wrap.style.cssText = 'width:100%;max-width:560px;text-align:center;display:flex;flex-direction:column;gap:6px;';
      el('p', { parent: wrap, text: '— CREDITS —' }).style.cssText = 'font-size:0.85rem;color:#ffd84a;letter-spacing:0.22em;margin:0 0 6px;';
      const line = el('p', { parent: wrap, text: 'Handcrafted by The Crypto Donkey' });
      line.style.cssText = 'font-size:0.92rem;color:#fff5d8;letter-spacing:0.06em;margin:0;';
      const tip = el('p', { parent: wrap, text: 'Built on Nostr · Lightning · open relays' });
      tip.style.cssText = 'font-size:0.74rem;color:rgba(220,210,255,0.6);letter-spacing:0.06em;margin:0;';
      const npub = el('p', { parent: wrap, text: 'npub1mgvlrnf5hm9yf0n5mf9nqmvarhvxkc6remu5ec3vf8r0txqkuk7su0e7q2' });
      npub.style.cssText = 'font-size:0.66rem;color:rgba(180,140,255,0.55);font-family:monospace;letter-spacing:0.04em;margin:4px 0 0;word-break:break-all;';
    }
  };

  const rotate = (): void => {
    if (!attractPanel.isConnected) {
      if (phaseTimer !== null) { window.clearTimeout(phaseTimer); phaseTimer = null; }
      return;
    }
    // Fade out, swap, fade in. setTimeout chain keeps the crossfade
    // visible without needing CSS @keyframes.
    attractPanel.style.opacity = '0';
    window.setTimeout(() => {
      if (!attractPanel.isConnected) return;
      phaseIdx = (phaseIdx + 1) % PHASE_ORDER.length;
      const next = PHASE_ORDER[phaseIdx];
      mountPhase(next);
      attractPanel.style.opacity = '1';
      phaseTimer = window.setTimeout(rotate, PHASE_DURATIONS[next]);
    }, 300);
  };
  // First panel — render immediately, no fade-in.
  mountPhase(PHASE_ORDER[0]);
  attractPanel.style.opacity = '1';
  phaseTimer = window.setTimeout(rotate, PHASE_DURATIONS[PHASE_ORDER[0]]);

  // The ONE thing on this screen — big PLAY button.
  const playRow = el('div', { className: 'menu-row', parent: overlay });
  const playBtn = el('button', { className: 'menu-btn', parent: playRow, text: 'PLAY ▶' }) as HTMLButtonElement;
  playBtn.style.cssText += 'font-size:1.4rem;padding:14px 48px;letter-spacing:0.28em;background:rgba(255,216,74,0.18);border-color:#ffd84a;color:#ffd84a;text-shadow:0 0 12px rgba(255,216,74,0.6);';
  playBtn.addEventListener('click', () => {
    void audio.unlockAudio();
    // Fullscreen MUST be requested in the same user-gesture tick. Sync
    // call (fire-and-forget) keeps the gesture chain alive. Silently
    // no-ops on iOS Safari which lacks the API.
    tryEnterFullscreen();
    if (state.session) {
      // Returning visitor with an identity — go straight to mission
      // select. The auth step is only for first-time visitors.
      renderTitle(state);
    } else {
      renderAuth(state, () => renderTitle(state));
    }
  });

  // Zap-us QR on attract — a walk-up at the booth can scan and send sats
  // before ever pressing PLAY (and the game-over recap auto-skips to title,
  // so this is the always-present place to catch them).
  renderZapUsQR(overlay, state, { caption: 'ZAP US ⚡' });

  // Footer — terms, privacy, version. Always visible on attract so the
  // legal surface is one tap away without cluttering the auth or
  // mission screens.
  renderLegalFooter(overlay);
}

export function renderAuth(state: GameState, onDone: () => void, opts?: { onResolved?: (s: SignetSession) => void; heading?: string; sub?: string; freshGuest?: boolean }): void {
  clearOverlay();
  const overlay = el('div', { className: 'overlay', parent: root });
  setupOverlayArrowNav(overlay);

  // When onResolved is supplied (capturing a SECOND player's identity at a
  // booth), it takes the resolved session instead of overwriting state.session.
  const resolve = (s: SignetSession): void => { if (opts?.onResolved) opts.onResolved(s); else state.session = s; };

  el('h2', { parent: overlay, text: opts?.heading ?? 'WHO ARE YOU?' });

  const sub = el('p', { parent: overlay, text: opts?.sub ?? 'Sign in with Nostr to take your name, your zaps, and your replays everywhere — or play as a guest and we\'ll create a local identity for you.' });
  sub.style.cssText = 'font-size:0.85rem;color:rgba(220,210,255,0.7);margin:6px auto 18px;max-width:560px;text-align:center;line-height:1.5;';

  // Option 1 — sign in with Nostr (existing Signet flow). The
  // SignInWithNostr button is the "advanced" path: NIP-07 extension,
  // NIP-46 bunker, or the SDK's QR-over-relay flow. We hand off to
  // auth.signIn() which manages the modal.
  const signInBtn = el('button', { className: 'menu-btn', parent: overlay, text: '⚡ SIGN IN WITH NOSTR' }) as HTMLButtonElement;
  signInBtn.style.cssText += 'font-size:1rem;padding:12px 32px;letter-spacing:0.18em;margin:6px auto;display:block;min-width:280px;';
  const signInStatus = el('p', { parent: overlay });
  signInStatus.style.cssText = 'font-size:0.78rem;color:rgba(180,140,255,0.85);min-height:1em;margin:0 0 12px;letter-spacing:0.04em;text-align:center;';
  let signing = false;
  signInBtn.addEventListener('click', () => {
    if (signing) return;
    signing = true;
    signInStatus.textContent = 'Connecting…';
    void (async () => {
      try {
        const session = await auth.signIn();
        if (session) {
          resolve(session);
          onDone();
          return;
        }
        signInStatus.textContent = 'No signer attached.';
        signInStatus.style.color = '#ff8a3a';
      } catch (err) {
        if (auth.isAuthOnlySignerError(err)) {
          signInStatus.textContent = 'Signer is not live. Choose a My Signet signing method.';
          signInStatus.style.color = '#ffd84a';
          renderSignerRecovery(state, { onResolved: resolve, onClose: onDone });
        } else {
          signInStatus.textContent = err instanceof auth.SignInTimeoutError
            ? `Timeout — ${err.message}`
            : `Sign-in failed: ${err instanceof Error ? err.message : String(err)}`;
          signInStatus.style.color = '#ff5050';
        }
      } finally {
        signing = false;
      }
    })();
  });

  // Visual separator between the two paths.
  const sep = el('div', { parent: overlay, text: '— OR —' });
  sep.style.cssText = 'font-family:monospace;color:rgba(220,210,255,0.4);letter-spacing:0.3em;margin:14px 0;text-align:center;';

  // Option 2 — guest. Arcade name picker + opt-out follow checkbox.
  // The picker is the same renderArcadeName the title's session
  // panel uses, so d-pad / touch / kb parity is automatic.
  el('p', { parent: overlay, text: '🚀 PLAY AS GUEST' }).style.cssText = 'font-size:1rem;letter-spacing:0.18em;color:#8cffb4;margin:0 0 8px;text-align:center;';

  const guestStatus = el('p', { parent: overlay });
  guestStatus.style.cssText = 'font-size:0.78rem;color:rgba(180,140,255,0.85);min-height:1em;margin:0;letter-spacing:0.04em;text-align:center;';

  let creating = false;
  const submitGuest = (raw: string): void => {
    if (creating) return;
    creating = true;
    guestStatus.textContent = '';
    try { void audio.unlockAudio(); } catch { /* ignore */ }
    void (async () => {
      try {
        const name = raw.trim() || 'Anonymous';
        // Read the opt-out checkbox state at submit time. Defaults
        // to true (pre-checked) so a user who just types and submits
        // gets the auto-follow.
        const followCheckEl = overlay.querySelector<HTMLInputElement>('input[data-follow-pallasite]');
        const followPallasite = followCheckEl?.checked ?? true;
        // Booth / kiosk: each walk-up is a different person, so mint a fresh
        // named identity (publishing their kind 0 + Pallasite follow) instead of
        // reusing the device's stored guest record from the previous player.
        resolve(await auth.createGuestSession(name, { followPallasite, fresh: opts?.freshGuest }));
        onDone();
      } catch (err) {
        guestStatus.textContent = `Couldn't create local identity: ${err instanceof Error ? err.message : String(err)}`;
        guestStatus.style.color = '#ff8a3a';
        creating = false;
      }
    })();
  };

  const picker = renderArcadeName(overlay, {
    maxLen: 25,
    onSubmit: (name) => submitGuest(name),
  });
  // Expose the in-progress name accessor in case a future PLAY-anywhere
  // shortcut on this screen wants to read it (matches the title-screen
  // pattern).
  titleNamePickerGetName = picker.getCurrentName;

  // Opt-out follow checkbox. Pre-checked so the default path publishes
  // a kind 3 contact list following the Pallasite game npub when the
  // guest identity is first created — disclosure is the point.
  // The actual publish happens in the kind-0 / kind-3 wiring (task #123);
  // this UI element reads its state at submit time.
  const followRow = el('label', { parent: overlay });
  followRow.style.cssText = 'display:flex;align-items:center;justify-content:center;gap:8px;font-size:0.78rem;color:rgba(220,210,255,0.7);margin:6px auto 0;cursor:pointer;letter-spacing:0.04em;max-width:480px;';
  const followCheck = el('input', { parent: followRow }) as HTMLInputElement;
  followCheck.type = 'checkbox';
  followCheck.checked = true;
  followCheck.dataset.followPallasite = '1';
  followCheck.style.cssText = 'width:16px;height:16px;accent-color:#8cffb4;cursor:pointer;';
  el('span', { parent: followRow, text: 'Follow Pallasite on Nostr for daily seeds + run highlights' });

  // Back to attract.
  const backRow = el('div', { className: 'menu-row', parent: overlay });
  const backBtn = el('button', { className: 'menu-btn secondary', parent: backRow, text: '◀ BACK' }) as HTMLButtonElement;
  backBtn.style.cssText += 'font-size:0.78rem;padding:6px 18px;letter-spacing:0.16em;';
  backBtn.addEventListener('click', () => renderAttract(state));
}

/**
 * Faucet status chip. Shows a single live/paused signal plus the daily-cap
 * meter — never the absolute float or lifetime payout, since advertising
 * pot size is a honey-pot for abuse. Polled every 60s while the title is
 * visible.
 */
function renderPoolChip(parent: HTMLElement): void {
  const wrapper = el('div', { parent });
  wrapper.style.cssText =
    'display:flex;flex-direction:column;align-items:center;gap:4px;margin:6px 0 4px';

  const lineStatus = el('p', { parent: wrapper });
  lineStatus.style.cssText =
    'font-size:0.78rem;color:rgba(255,216,74,0.65);letter-spacing:0.08em;margin:0';
  lineStatus.textContent = 'Faucet: …';

  // Daily-faucet meter: thin horizontal bar + spent/cap text. Hidden until
  // the first /api/pool response with daily_cap_sats arrives.
  const meterWrap = el('div', { parent: wrapper });
  meterWrap.style.cssText =
    'display:none;flex-direction:column;align-items:center;gap:2px;width:200px;margin-top:4px';

  const meterBar = el('div', { parent: meterWrap });
  meterBar.style.cssText =
    'width:100%;height:4px;background:rgba(255,255,255,0.08);border-radius:2px;overflow:hidden';

  const meterFill = el('div', { parent: meterBar });
  meterFill.style.cssText =
    'height:100%;width:0%;background:#58ff58;transition:width 600ms ease,background 400ms ease';

  const meterLabel = el('p', { parent: meterWrap });
  meterLabel.style.cssText =
    'font-size:0.72rem;color:rgba(180,180,180,0.7);letter-spacing:0.08em;margin:0';

  let intervalId: number | null = null;

  const update = async (): Promise<void> => {
    const pool = await fetchPool();
    if (!wrapper.isConnected) {
      if (intervalId !== null) clearInterval(intervalId);
      return;
    }
    if (!pool) {
      lineStatus.textContent = 'Faucet status unavailable';
      lineStatus.style.color = 'rgba(180,180,180,0.6)';
      meterWrap.style.display = 'none';
      return;
    }
    if (pool.paused) {
      lineStatus.textContent = 'Faucet paused';
      lineStatus.style.color = '#ff8050';
    } else {
      lineStatus.textContent = 'Faucet active';
      lineStatus.style.color = 'rgba(255,216,74,0.65)';
    }

    // Daily meter — green / amber / red as the cap fills.
    if (typeof pool.daily_cap_sats === 'number' && pool.daily_cap_sats > 0) {
      const spent = pool.daily_spent_sats ?? 0;
      const pct = Math.min(100, Math.round((spent / pool.daily_cap_sats) * 100));
      meterFill.style.width = `${pct}%`;
      let colour = '#58ff58'; // green
      if (pct >= 90) colour = '#ff5050';
      else if (pct >= 60) colour = '#ffd84a';
      meterFill.style.background = colour;
      meterLabel.textContent =
        pct >= 100
          ? `Today's faucet drained — back tomorrow`
          : `Today: ${spent.toLocaleString()} of ${pool.daily_cap_sats.toLocaleString()} sats`;
      meterWrap.style.display = 'flex';
    } else {
      meterWrap.style.display = 'none';
    }
  };

  void update();
  intervalId = window.setInterval(() => {
    if (!wrapper.isConnected) {
      if (intervalId !== null) clearInterval(intervalId);
      return;
    }
    void update();
  }, 60_000);
}

/** Title/attract leaderboard read cap — see the deferral note in
 *  renderGlobalLeaderboard. Scores are replicated across every active relay
 *  (publishScore fans out to all), so the first few primaries surface the same
 *  global top without holding a socket open to all ~7. */
const LEADERBOARD_RELAY_CAP = 3;

function renderGlobalLeaderboard(parent: HTMLElement, state: GameState, board: ScoreBoardId = 'solo'): void {
  const container = el('div', { parent });
  const block = el('div', { className: 'leaderboard-block', parent: container });
  const titleText = board === 'coop-campaign' ? '— GLOBAL CO-OP CAMPAIGN —' : '— GLOBAL HIGH SCORES —';
  el('p', { className: 'leaderboard-title', parent: block, text: titleText });
  const status = el('p', { parent: block, text: 'Listening to relays…' });
  status.style.cssText = 'font-size:0.85rem;color:rgba(180,140,255,0.7);letter-spacing:0.06em;margin:0;';

  // Persistent subscription: scores stream in as relays propagate them and
  // the leaderboard reflects the new state without reloading the title. The
  // 30s cache that fetchGlobalHighScores used to apply is bypassed here on
  // purpose -- we want live updates, not polled snapshots.
  let renderToken = 0;
  let receivedAny = false;
  let cleanupTimer: number | null = null;
  let unsubscribe: (() => void) | null = null;
  let cancelled = false;

  const teardown = (): void => {
    cancelled = true;
    if (unsubscribe) { unsubscribe(); unsubscribe = null; }
    if (cleanupTimer !== null) { clearInterval(cleanupTimer); cleanupTimer = null; }
  };

  // Defer the relay subscription off the first-paint critical path. Subscribing
  // synchronously opens a socket to every active relay the instant the title
  // draws — a no-interaction, multi-host fan-out that reads as beacon-like to
  // network-reputation scanners. The "Listening to relays…" placeholder is
  // already on screen, so idle warm-up fills it a beat later. Reads a capped
  // primary subset too (see LEADERBOARD_RELAY_CAP). Same idiom as the ghost
  // prefetch + deferProfileFetch.
  const startSubscription = (): void => {
    if (cancelled || !container.isConnected) return;
    const relays = getActiveRelays().slice(0, LEADERBOARD_RELAY_CAP);
    unsubscribe = subscribeGlobalHighScores(async raw => {
      if (!container.isConnected) { teardown(); return; }
      receivedAny = true;
      if (raw.length === 0) {
        status.textContent = 'No global scores yet — be the first.';
        return;
      }
      const myToken = ++renderToken;
      const top = raw.slice(0, 5);
      const localHint = state.session?.displayName
        ? { pubkey: state.session.pubkey, displayName: state.session.displayName }
        : null;
      const entries = await Promise.all(top.map(e => resolveDisplayName(e, localHint)));
      if (!container.isConnected || myToken !== renderToken) return;
      container.innerHTML = '';
      renderLeaderboardBlock(container, entries.map(globalToLocal), titleText, 5, () => renderTitle(state));
    }, { board, relays });
  };
  if (typeof window.requestIdleCallback === 'function') {
    window.requestIdleCallback(startSubscription, { timeout: 2500 });
  } else {
    window.setTimeout(startSubscription, 1000);
  }

  // Backstop probe: if the title screen unmounts during a long quiet period
  // the onUpdate-side disconnection check won't fire. Probe every 30s.
  cleanupTimer = window.setInterval(() => {
    if (!container.isConnected) teardown();
  }, 30_000);

  // Empty-state fallback if relays stay silent for 8s -- soften "Listening…"
  // into the same "be the first" hint fetchGlobalHighScores used to show.
  window.setTimeout(() => {
    if (!container.isConnected) return;
    if (!receivedAny && status.isConnected) {
      status.textContent = 'No global scores yet — be the first.';
    }
  }, 8000);
}

async function resolveDisplayName(
  entry: GlobalHighScore,
  localHint?: { pubkey: string; displayName: string } | null,
): Promise<GlobalHighScore & { displayName: string }> {
  const cached = getCachedProfile(entry.pubkey);
  const profile = cached ?? await fetchProfile(entry.pubkey).catch(() => null);
  const hasProfileName = !!(profile?.display_name?.trim() || profile?.name?.trim());
  // Persona parity with guests: if this row is the local player on a persona
  // that shares a handle but has no published kind-0 yet, show that handle
  // rather than a bare pubkey. A real kind-0 still wins (so it matches what
  // Gamestr/other clients resolve) — My Signet publishing a kind-0 per persona
  // is the cross-client fix.
  const localName = localHint && entry.pubkey.toLowerCase() === localHint.pubkey.toLowerCase()
    ? localHint.displayName.trim()
    : '';
  const displayName = hasProfileName ? bestName(profile, entry.pubkey) : (localName || bestName(null, entry.pubkey));
  return { ...entry, displayName };
}

function globalToLocal(entry: GlobalHighScore & { displayName: string }): ReturnType<typeof getLocalHighScores>[number] {
  return {
    name: entry.displayName,
    score: entry.score,
    sats: entry.sats,
    wave: entry.wave,
    at: entry.at,
    pubkey: entry.pubkey,
    eventId: entry.eventId,
  };
}

/**
 * Mode picker — campaign / co-op / drift / bossrush / arena. Shape of the run.
 * Selected mode highlights yellow; unfinished modes (bossrush, arena)
 * still render so the player knows they're coming, but tapping them
 * toasts COMING SOON and the selection reverts to the previous valid
 * mode.
 */
function leaveMultiplayerUrlSessionForMode(mode: RunMode): void {
  if (mode === 'duel' || mode === 'coop-campaign' || mode === 'deathmatch') return;
  try {
    (window as unknown as { __pallasiteExitMultiplayerSession?: () => void }).__pallasiteExitMultiplayerSession?.();
  } catch { /* ignore */ }

  try {
    const url = new URL(window.location.href);
    const params = url.searchParams;
    const multiplayerKeys = [
      'mode', 'coop', 'deathmatch', 'peer', 'session', 'slot', 'spectate',
      'players', 'deathmatchPlayers', 'peerBatch', 'batchFrames', 'aiFill',
      'humanSlots', 'inputDelay', 'wiretrace',
      'deathmatchTime', 'deathmatchKills', 'deathmatchRespawns', 'deathmatchAiSkill',
      'dmTime', 'dmKills', 'dmRespawns', 'dmAiSkill',
      'deathmatchAi', 'autoStart', 'autostart',
    ];
    let changed = false;
    for (const key of multiplayerKeys) {
      if (!params.has(key)) continue;
      params.delete(key);
      changed = true;
    }
    if (changed) {
      const search = params.toString();
      window.history.replaceState(null, '', `${url.pathname}${search ? `?${search}` : ''}${url.hash}`);
    }
  } catch { /* ignore */ }
}

function renderModeRow(parent: HTMLElement, state: GameState): void {
  const wrapper = el('div', { parent });
  wrapper.style.cssText = 'display:flex;flex-direction:column;gap:8px;align-items:center;';
  const label = el('p', { parent: wrapper, text: 'MODE' });
  label.style.cssText = 'font-size:0.8rem;color:rgba(180,140,255,0.85);letter-spacing:0.3em;margin:0;';

  const row = el('div', { parent: wrapper });
  row.style.cssText = 'display:flex;gap:6px;flex-wrap:wrap;justify-content:center;';

  const hint = el('p', { parent: wrapper });
  hint.style.cssText = 'font-size:0.78rem;color:rgba(180,140,255,0.7);letter-spacing:0.06em;margin:0;height:1em;text-align:center;';

  const buttons = new Map<RunMode, HTMLButtonElement>();
  const refresh = (): void => {
    const current = getStoredMode();
    for (const info of MODE_LIST) {
      const btn = buttons.get(info.id)!;
      const selected = info.id === current;
      btn.style.cssText = [
        'background:' + (selected ? 'rgba(255,216,74,0.18)' : 'transparent'),
        'border:2px solid ' + (selected ? '#ffd84a' : info.ready ? 'rgba(180,140,255,0.4)' : 'rgba(180,140,255,0.18)'),
        'color:' + (selected ? '#ffd84a' : info.ready ? 'rgba(220,210,255,0.85)' : 'rgba(180,140,255,0.45)'),
        "font-family:'VT323',ui-monospace,monospace",
        'font-size:0.95rem', 'padding:6px 14px',
        'letter-spacing:0.16em', 'cursor:pointer', 'border-radius:6px',
        'transition:all 0.12s ease',
        selected ? 'box-shadow:0 0 14px rgba(255,216,74,0.4);text-shadow:0 0 6px rgba(255,216,74,0.6)' : '',
      ].filter(Boolean).join(';');
    }
    const hintFor = MODE_LIST.find(m => m.id === current)?.hint ?? '';
    hint.textContent = hintFor;
  };

  for (const info of MODE_LIST) {
    const btn = el('button', { parent: row, text: info.label });
    buttons.set(info.id, btn);
    onTap(btn, () => {
      if (!info.ready) {
        hint.textContent = 'COMING SOON';
        return;
      }
      const prev = getStoredMode();
      setStoredMode(info.id);
      lockInMode(info.id);
      leaveMultiplayerUrlSessionForMode(info.id);
      // Re-fit so the renderMode picks up the new mode's camera /
      // background / radar settings (Defender uses landscape follow +
      // parallax bg + forced radar — without a refit those wouldn't
      // engage until the next browser resize event).
      try { (window as unknown as { __pallasiteFit?: () => void }).__pallasiteFit?.(); } catch { /* ignore */ }
      // Toggling in/out of lobby-backed modes changes the IGNITE button
      // label/behaviour and the leaderboard board, so re-render the title
      // rather than keep those separate DOM islands in sync by hand.
      if (prev === 'duel' || prev === 'coop-campaign' || prev === 'deathmatch' || info.id === 'duel' || info.id === 'coop-campaign' || info.id === 'deathmatch') {
        renderTitle(state);
      } else {
        refresh();
      }
    });
    btn.addEventListener('mouseenter', () => { hint.textContent = info.hint; });
    btn.addEventListener('mouseleave', () => {
      hint.textContent = MODE_LIST.find(m => m.id === getStoredMode())?.hint ?? '';
    });
  }
  refresh();
}

